from datetime import datetime, timedelta
import pytest
from app.ai.stages import extract_viewing_datetime

def test_extract_tomorrow_with_pm_time():
    now = datetime(2026, 5, 19, 9, 0)
    messages = [
        {"sender": "landlord", "message": "I can do 5pm or 7pm tomorrow."}
    ]
    # Expect 7pm tomorrow (2026-05-20 19:00)
    expected = datetime(2026, 5, 20, 19, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

def test_extract_named_weekday_and_time_with_multiple_messages():
    now = datetime(2026, 5, 19, 9, 0)  # Tuesday
    messages = [
        {"sender": "landlord", "message": "Confirmed, see you tomorrow at 6pm."},
        {"sender": "landlord", "message": "Can we reschedule? Thursday at 8pm works."}
    ]
    # Thursday after 2026-05-19 is 2026-05-21
    expected = datetime(2026, 5, 21, 20, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

def test_extract_explicit_date_and_afternoon_time():
    now = datetime(2026, 6, 4, 9, 0)
    messages = [
        {"sender": "landlord", "message": "Confirmed for 05/06 at 3."}
    ]
    # 05/06 means 5 June 2026, time 3 interpreted as 15:00
    expected = datetime(2026, 6, 5, 15, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

def test_extract_tomorrow_and_time_without_am_pm():
    now = datetime(2026, 6, 4, 17, 0)
    messages = [
        {"sender": "landlord", "message": "Viewing booked for tomorrow at 3."}
    ]
    # tomorrow = 2026-06-05, time 3 interpreted as 15:00
    expected = datetime(2026, 6, 5, 15, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

def test_case_insensitive_matching_and_mid_sentence_keywords():
    now = datetime(2026, 7, 1, 10, 0)  # Thursday
    messages = [
        {"sender": "landlord", "message": "The viewing is CONFIRMED for Tomorrow at 8PM."}
    ]
    # tomorrow = 2026-07-02, time 8pm = 20:00
    expected = datetime(2026, 7, 2, 20, 0)
